public class Josephus {

    static class Node {
        int pos; Node next;
        Node(int p) { pos = p; }
    }

    public int solve(int n, int k) {
        // Build circular list for positions 1..n
        Node head = new Node(1);
        Node tail = head;
        for (int i = 2; i <= n; i++) {
            tail.next = new Node(i);
            tail = tail.next;
        }
        tail.next = head; // make circular

        Node curr = head;
        int remaining = n;

        while (remaining > 1) {
            // TODO: advance k-1 steps from curr
            // remove the k-th node (curr.next)
            // continue from the node after removal
            remaining--;
        }
        return curr.pos;
    }

    public static void main(String[] args) {
        Josephus j = new Josephus();
        System.out.println(j.solve(6, 2));
        System.out.println(j.solve(7, 3));
        System.out.println(j.solve(1, 1));
    }
}

